// lib/notificationService.ts
import { createClient } from '@supabase/supabase-js';
import { getIO } from './socketServer';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;
const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY!;

// Use service role for admin operations
const supabaseAdmin = createClient(supabaseUrl, supabaseServiceKey);
const supabase = createClient(supabaseUrl, supabaseAnonKey);

type Actor = {
  id: string;
  name?: string;
  avatar_url?: string;
};

// Enhanced logging helper
function logError(context: string, error: any, metadata?: any) {
  const timestamp = new Date().toISOString();
  console.error(`[${timestamp}] [notificationService:${context}]`, {
    error: error?.message || error,
    code: error?.code,
    details: error?.details,
    metadata
  });
}

function logInfo(context: string, message: string, metadata?: any) {
  const timestamp = new Date().toISOString();
  console.log(`[${timestamp}] [notificationService:${context}]`, message, metadata || '');
}

export async function createNotification(
  recipientId: string,
  senderId: string | null,
  type: string,
  content: string,
  link?: string,
  options?: { aggregationKey?: string; latestActor?: Actor }
) {
  try {
    // Validate required parameters
    if (!recipientId || !type || !content) {
      const error = new Error('Missing required parameters: recipientId, type, or content');
      logError('createNotification', error, { recipientId, type, content });
      return { data: null, error };
    }

    const aggregationKey = options?.aggregationKey;
    const latestActor = options?.latestActor ?? (senderId ? { id: senderId } : undefined);

    // If an aggregation key is provided and we have a sender, try to upsert
    if (aggregationKey && senderId) {
      const { data: existing, error: findError } = await supabaseAdmin
        .from('notifications')
        .select('*')
        .eq('recipient_id', recipientId)
        .eq('type', type)
        .eq('aggregation_key', aggregationKey)
        .eq('is_read', false)
        .order('updated_at', { ascending: false })
        .limit(1);

      if (findError) {
        logError('findExisting', findError, { recipientId, type, aggregationKey });
        return { data: null, error: findError };
      }

      const existingRow = existing && existing.length > 0 ? existing[0] : null;

      if (existingRow) {
        // Merge latest_actors (de-dupe by id, keep most recent first, cap at 3)
        const prevActors: Actor[] = Array.isArray(existingRow.latest_actors)
          ? existingRow.latest_actors
          : [];
        const filtered = latestActor
          ? [latestActor, ...prevActors.filter((a: any) => a && a.id !== latestActor.id)]
          : prevActors;
        const mergedActors = filtered.slice(0, 3);
        const newCount = (existingRow.count ?? 1) + 1;

        const { data: updated, error: updateError } = await supabaseAdmin
          .from('notifications')
          .update({
            count: newCount,
            latest_actors: mergedActors as any,
            updated_at: new Date().toISOString(),
          })
          .eq('id', existingRow.id)
          .select('*')
          .limit(1);

        if (updateError) {
          logError('aggregateUpdate', updateError, { notificationId: existingRow.id });
          return { data: null, error: updateError };
        }

        const updatedRow = updated && updated.length > 0 ? updated[0] : existingRow;
        logInfo('aggregateUpdate', 'Notification aggregated', { id: updatedRow.id, count: newCount });

        // Emit real-time update to recipient room
        try {
          const io = getIO();
          if (io) {
            io.to(recipientId).emit('notification_updated', updatedRow);
            logInfo('socketEmit', 'notification_updated event sent', { recipientId });
          }
        } catch (e) {
          // Non-fatal: socket emission failure shouldn't break notifications
          logError('socketEmit', e, { event: 'notification_updated', recipientId });
        }

        return { data: updatedRow, error: null };
      }

      // No existing: insert a new aggregated notification
      const insertPayload: any = {
        recipient_id: recipientId,
        sender_id: senderId,
        type,
        content,
        link,
        aggregation_key: aggregationKey,
        count: 1,
        latest_actors: latestActor ? [latestActor] : [],
      };

      const { data: inserted, error: insertError } = await supabaseAdmin
        .from('notifications')
        .insert([insertPayload])
        .select('*')
        .limit(1);

      if (insertError) {
        logError('aggregateInsert', insertError, { type, aggregationKey });
        return { data: null, error: insertError };
      }

      const newRow = inserted && inserted.length > 0 ? inserted[0] : null;
      logInfo('aggregateInsert', 'New aggregated notification created', { id: newRow?.id, type });
      
      try {
        const io = getIO();
        if (io && newRow) {
          io.to(recipientId).emit('new-notification', newRow);
          logInfo('socketEmit', 'new-notification event sent', { recipientId });
        }
      } catch (e) {
        logError('socketEmit', e, { event: 'new-notification', recipientId });
      }

      return { data: newRow, error: null };
    }

    // Non-aggregated: simple insert
    const { data, error } = await supabaseAdmin
      .from('notifications')
      .insert([{ recipient_id: recipientId, sender_id: senderId, type, content, link }])
      .select('*')
      .limit(1);

    if (error) {
      logError('simpleInsert', error, { type });
      return { data: null, error };
    }

    const row = data && data.length > 0 ? data[0] : null;
    logInfo('simpleInsert', 'New notification created', { id: row?.id, type });

    try {
      const io = getIO();
      if (io && row) {
        io.to(recipientId).emit('new-notification', row);
        logInfo('socketEmit', 'new-notification event sent', { recipientId });
      }
    } catch (e) {
      logError('socketEmit', e, { event: 'new-notification', recipientId });
    }

    return { data: row, error: null };
  } catch (e: any) {
    logError('createNotification', e, { recipientId, type });
    return { data: null, error: e };
  }
}

export async function getNotifications(recipientId: string, limit = 20, offset = 0) {
  try {
    if (!recipientId) {
      const error = new Error('recipientId is required');
      logError('getNotifications', error);
      return { data: null, error };
    }

    const { data, error } = await supabase
      .from('notifications')
      .select('*')
      .eq('recipient_id', recipientId)
      .order('created_at', { ascending: false })
      .range(offset, offset + limit - 1);

    if (error) {
      logError('getNotifications', error, { recipientId, limit, offset });
    }

    return { data, error };
  } catch (e: any) {
    logError('getNotifications', e, { recipientId });
    return { data: null, error: e };
  }
}

export async function markNotificationsRead(recipientId: string, notificationIds?: string[]) {
  try {
    if (!recipientId) {
      const error = new Error('recipientId is required');
      logError('markNotificationsRead', error);
      return { data: null, error };
    }

    let query = supabase
      .from('notifications')
      .update({ is_read: true })
      .eq('recipient_id', recipientId);
    
    if (notificationIds && notificationIds.length > 0) {
      query = query.in('id', notificationIds);
    }
    
    const { data, error } = await query;

    if (error) {
      logError('markNotificationsRead', error, { recipientId, count: notificationIds?.length });
    } else {
      logInfo('markNotificationsRead', 'Notifications marked as read', { 
        recipientId, 
        count: notificationIds?.length || 'all' 
      });
    }

    return { data, error };
  } catch (e: any) {
    logError('markNotificationsRead', e, { recipientId });
    return { data: null, error: e };
  }
}
