import { NextRequest, NextResponse } from 'next/server'
import { createClient } from '@supabase/supabase-js'
import { createNotification } from '@/lib/notificationService'

// Ensure Node runtime for Buffer/base64 helpers
export const runtime = 'nodejs'

// Simple in-memory cache for user profiles (cache for 30 seconds)
const profileCache = new Map<string, { data: any; timestamp: number }>()
const CACHE_TTL = 30000 // 30 seconds

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!
const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY

export async function POST(request: NextRequest) {
  try {
    const body = await request.json()
    const { action } = body

    // Base Supabase client (no user auth)
    const supabase = createClient(supabaseUrl, supabaseAnonKey, {
      auth: { persistSession: false, autoRefreshToken: false }
    })

    // Get user from authorization header and/or x-user-id
    const authHeader = request.headers.get('Authorization')
    const userIdHeader = request.headers.get('x-user-id')

    let userId: string | null = null
    let authToken: string | null = null

    // Helper: decode JWT payload safely to extract `sub` without verifying signature
    const decodeJwtSub = (token: string): string | null => {
      try {
        const parts = token.split('.')
        if (parts.length !== 3) return null
        const payload = JSON.parse(Buffer.from(parts[1].replace(/-/g, '+').replace(/_/g, '/'), 'base64').toString('utf8'))
        return payload?.sub || null
      } catch {
        return null
      }
    }

    if (authHeader && authHeader.startsWith('Bearer ')) {
      const tokenCandidate = authHeader.replace('Bearer ', '')
      // Always capture the token so we can create an authed client for RLS
      authToken = tokenCandidate
      // Best-effort: ask Supabase to validate and also try decoding the JWT locally
      try {
        const { data: { user } } = await supabase.auth.getUser(tokenCandidate)
        if (user?.id) {
          userId = user.id
        }
      } catch {
        // ignore
      }
      if (!userId) {
        userId = decodeJwtSub(tokenCandidate)
      }
    }
    // If we have a token, create an authed client so RLS sees auth.uid()
    const authedClient = authToken
      ? createClient(supabaseUrl, supabaseAnonKey, {
          auth: { persistSession: false, autoRefreshToken: false },
          global: { headers: { Authorization: `Bearer ${authToken}` } }
        })
      : null

    // Always create admin client if available (used only as fallback for expired tokens)
    const adminClient = (supabaseServiceKey)
      ? createClient(supabaseUrl, supabaseServiceKey, {
          auth: { persistSession: false, autoRefreshToken: false }
        })
      : null

    // Fallback to x-user-id if token missing or cannot decode `sub`
    if (!userId && userIdHeader) {
      userId = userIdHeader
    }

    switch (action) {
      case 'get-profile':
        if (!userId && !authedClient && !adminClient) {
          return NextResponse.json(
            { error: 'Authentication required', success: false },
            { status: 401 }
          )
        }

        // Check cache first
        const cacheKey = `profile_${userId}`
        const cached = profileCache.get(cacheKey)
        if (cached && Date.now() - cached.timestamp < CACHE_TTL) {
          console.log('[get-profile] Returning cached data for:', userId)
          return NextResponse.json(cached.data)
        }

        // Prefer authed/admin client so RLS recognizes auth.uid(); fallback to admin on expired JWT
        const profileClient = authedClient || adminClient || supabase
        
        // Add timeout wrapper to prevent hanging requests
        const fetchWithTimeout = <T,>(promise: Promise<T>, timeoutMs = 30000): Promise<T> => {
          const timeoutPromise = new Promise<T>((_, reject) => 
            setTimeout(() => reject(new Error('Request timeout')), timeoutMs)
          )
          return Promise.race([promise, timeoutPromise])
        }

        let userProfile: any = null
        let profileError: any = null

        try {
          console.log('[get-profile] Querying users table for id:', userId)
          const startTime = Date.now()
          const result: any = await fetchWithTimeout(
            Promise.resolve(
              profileClient
                .from('users')
                .select('*, barangays(name, municipality)')
                .eq('id', userId)
                .maybeSingle()
            )
          )
          const duration = Date.now() - startTime
          console.log(`[get-profile] Query complete in ${duration}ms`)
          userProfile = result.data
          profileError = result.error
        } catch (err: any) {
          if (err && err.message === 'Request timeout') {
            console.error('[get-profile] error: Request timeout')
            return NextResponse.json(
              { error: 'Request timeout', success: false },
              { status: 504 }
            )
          }
          console.error('[get-profile] Query failed:', err)
          profileError = err
        }

        if (profileError && adminClient && (/JWT expired/i.test(profileError.message || '') || profileError?.code === 'PGRST303')) {
          try {
            const result: any = await fetchWithTimeout(
              Promise.resolve(
                adminClient!
                  .from('users')
                  .select('*')
                  .eq('id', userId as string)
                  .maybeSingle()
              )
            )
            userProfile = result.data
            profileError = result.error
          } catch (err: any) {
            profileError = err
          }
        }

        if (profileError) {
          // Log full error object for backend visibility
          console.error('[get-profile] error:', profileError);
          // Return detailed error info for frontend debugging
          const errorDetails = {
            code: profileError?.code || null,
            message: profileError?.message || profileError?.toString() || 'Unknown error',
            hint: profileError?.hint || null,
            details: profileError?.details || null
          };
          if (errorDetails.code === 'PGRST303' || /JWT expired/i.test(errorDetails.message)) {
            return NextResponse.json(
              { error: 'Session expired', success: false, details: errorDetails },
              { status: 401 }
            )
          }
          return NextResponse.json(
            { error: 'Failed to fetch user profile', success: false, details: errorDetails },
            { status: 500 }
          )
        }

        if (!userProfile && adminClient && userId) {
          // Attempt to create missing profile using admin client
          try {
            // Try to extract registration data from request body if available
            let regData: any = {};
            try {
              regData = typeof body === 'object' ? body : {};
            } catch {}
            const newProfile = {
              id: userId,
              email: regData.email || '',
              full_name: regData.full_name || regData.name || regData.username || 'User',
              username: regData.username || regData.full_name || regData.name || 'user',
              phone: regData.phone || '',
              bio: '',
              location: '',
              interests: [],
              profile_image_url: '',
              is_public: true,
              is_seller: false,
              is_active: true,
              eco_points: 0,
              total_donations: 0,
              total_co2_saved: 0,
              donated_devices: 0,
              recycled_devices: 0,
              created_at: new Date().toISOString(),
              updated_at: new Date().toISOString()
            }
            const { error: insertError } = await adminClient
              .from('users')
              .insert(newProfile)
            if (!insertError) {
              // Fetch the newly created profile
              const { data: createdProfile, error: fetchError } = await adminClient
                .from('users')
                .select('*')
                .eq('id', userId)
                .maybeSingle()
              if (createdProfile) {
                userProfile = createdProfile
              }
            }
          } catch (err) {
            // ignore, fallback to error below
          }
        }
        if (!userProfile) {
          return NextResponse.json(
            { error: 'User profile not found', success: false },
            { status: 404 }
          )
        }

        const userData = {
          id: userProfile.id,
          email: userProfile.email,
          full_name: userProfile.full_name || 'User',
          username: userProfile.username || 'user',
          phone: userProfile.phone || '',
          bio: userProfile.bio || '',
          location: userProfile.location || '',
          interests: userProfile.interests || [],
          profile_image_url: userProfile.profile_image_url || '',
          is_public: userProfile.is_public !== false,
          is_seller: userProfile.is_seller || false,
          eco_points: userProfile.eco_points || 0,
          total_donations: userProfile.total_donations || 0,
          total_co2_saved: userProfile.total_co2_saved || 0,
          donated_devices: userProfile.donated_devices || 0,
          recycled_devices: userProfile.recycled_devices || 0,
          created_at: userProfile.created_at,
          barangay_id: userProfile.barangay_id || null,
          barangays: userProfile.barangays || null
        }

        // Recalculate eco_points from accepted donations only (source of truth)
        try {
          const donationClient = authedClient || adminClient || supabase
          const { data: acceptedDonations } = await donationClient
            .from('donations')
            .select('eco_points_earned, co2_saved')
            .eq('user_id', userProfile.id)
            .in('status', ['accepted', 'approved'])

          if (acceptedDonations) {
            userData.eco_points = acceptedDonations.reduce((sum: number, d: any) => sum + (d.eco_points_earned || 0), 0)
            userData.total_co2_saved = Math.round(acceptedDonations.reduce((sum: number, d: any) => sum + (d.co2_saved || 0), 0) * 100) / 100
            userData.total_donations = acceptedDonations.length
          }
        } catch (err) {
          console.error('[get-profile] Error recalculating eco_points from donations:', err)
          // Fall back to stored values if donation query fails
        }

        console.log('📦 [get-profile] Returning user data with barangay:', {
          barangay_id: userData.barangay_id,
          has_barangays: !!userData.barangays
        })

        const achievements = generateAchievements(userData)

        const responseData = {
          success: true,
          user: userData,
          achievements: achievements
        }

        // Cache the response
        profileCache.set(cacheKey, {
          data: responseData,
          timestamp: Date.now()
        })

        return NextResponse.json(responseData)

      case 'get-leaderboard':
        console.log('[get-leaderboard] Fetching top users')
        const leaderboardStartTime = Date.now()
        
        const leaderboardClient = authedClient || adminClient || supabase
        
        // Try with authed client first
        let { data: topUsers, error: leaderboardError } = await leaderboardClient
          .from('users')
          .select('id, full_name, username, profile_image_url, eco_points, total_donations, total_co2_saved')
          .eq('is_public', true)
          .eq('is_active', true)
          .eq('is_admin', false)  // Exclude admin accounts from leaderboard
          .gte('eco_points', 0)  // Changed from gt to gte to include users with 0 points
          .order('eco_points', { ascending: false })
          .limit(10)

        // If JWT expired, retry with admin client
        if (leaderboardError && adminClient && (/JWT expired/i.test(leaderboardError.message || '') || leaderboardError?.code === 'PGRST303')) {
          console.log('[get-leaderboard] JWT expired, retrying with admin client')
          const result = await adminClient
            .from('users')
            .select('id, full_name, username, profile_image_url, eco_points, total_donations, total_co2_saved')
            .eq('is_public', true)
            .eq('is_active', true)
            .eq('is_admin', false)  // Exclude admin accounts from leaderboard
            .gte('eco_points', 0)
            .order('eco_points', { ascending: false })
            .limit(10)
          topUsers = result.data
          leaderboardError = result.error
        }

        const leaderboardDuration = Date.now() - leaderboardStartTime
        console.log(`[get-leaderboard] Query complete in ${leaderboardDuration}ms, found ${topUsers?.length || 0} users`)

        if (leaderboardError) {
          console.error('[get-leaderboard] Error:', leaderboardError)
          return NextResponse.json({
            success: true,
            leaderboard: []
          })
        }

        // For each user on the leaderboard, recalculate eco_points from accepted donations
        const leaderboardCalcClient = adminClient || authedClient || supabase
        const leaderboardWithRealPoints = await Promise.all(
          (topUsers || []).map(async (user) => {
            try {
              const { data: acceptedDonations } = await leaderboardCalcClient
                .from('donations')
                .select('eco_points_earned, co2_saved')
                .eq('user_id', user.id)
                .in('status', ['accepted', 'approved'])

              const realEcoPoints = (acceptedDonations || []).reduce((sum: number, d: any) => sum + (d.eco_points_earned || 0), 0)
              const realCo2 = Math.round((acceptedDonations || []).reduce((sum: number, d: any) => sum + (d.co2_saved || 0), 0) * 100) / 100
              const realDonations = (acceptedDonations || []).length

              return {
                ...user,
                eco_points: realEcoPoints,
                total_co2_saved: realCo2,
                total_donations: realDonations
              }
            } catch {
              return user // fall back to stored values
            }
          })
        )

        // Re-sort by real eco_points after recalculation
        leaderboardWithRealPoints.sort((a, b) => (b.eco_points || 0) - (a.eco_points || 0))

        const leaderboard = leaderboardWithRealPoints.map((user, index) => ({
          id: user.id,
          rank: index + 1,
          name: user.full_name || user.username || 'User',
          username: user.username || 'user',
          eco_points: user.eco_points || 0,
          total_donations: user.total_donations || 0,
          total_co2_saved: user.total_co2_saved || 0,
          profile_image_url: user.profile_image_url
        }))

        return NextResponse.json({
          success: true,
          leaderboard: leaderboard
        })

      case 'update-profile':
        if (!userId && !authedClient && !adminClient) {
          return NextResponse.json(
            { error: 'Authentication required', success: false },
            { status: 401 }
          )
        }

        const { phone, bio, location, interests, profile_image_url, is_public, barangay_id } = body

        const updateData: any = {
          updated_at: new Date().toISOString()
        }

        // Only update fields that are provided
        if (phone !== undefined) updateData.phone = phone
        if (bio !== undefined) updateData.bio = bio
        if (location !== undefined) updateData.location = location
        if (interests !== undefined) updateData.interests = interests
        if (profile_image_url !== undefined) updateData.profile_image_url = profile_image_url
        if (is_public !== undefined) updateData.is_public = is_public
        if (barangay_id !== undefined) {
          updateData.barangay_id = barangay_id || null
          console.log('🏘️ [update-profile] Barangay update:', {
            received: barangay_id,
            type: typeof barangay_id,
            willSave: updateData.barangay_id
          })
        }

        console.log('📝 [update-profile] Incoming:', {
          userId,
          updateData,
          hasBarangayId: 'barangay_id' in updateData,
          client: authedClient ? 'authedClient' : adminClient ? 'adminClient' : 'none'
        })

        const updateClient = authedClient || adminClient
        if (!updateClient) {
          console.error('❌ [update-profile] No updateClient available')
          return NextResponse.json(
            { error: 'Authentication required', success: false },
            { status: 401 }
          )
        }

        let { data: updatedProfile, error: updateError }: any = await updateClient
          .from('users')
          .update(updateData)
          .eq('id', userId as string)
          .select()
          .single()

        if (updateError && adminClient && (/JWT expired/i.test(updateError.message || '') || updateError?.code === 'PGRST303')) {
          ({ data: updatedProfile, error: updateError } = await adminClient!
            .from('users')
            .update(updateData)
            .eq('id', userId as string)
            .select()
            .single())
        }

        if (updateError) {
          console.error('❌ [update-profile] Update failed:', updateError)
          if ((updateError as any)?.code === 'PGRST303' || /JWT expired/i.test((updateError as any)?.message || '')) {
            return NextResponse.json(
              { error: 'Session expired', success: false },
              { status: 401 }
            )
          }
          return NextResponse.json(
            { error: 'Failed to update profile', success: false, details: updateError },
            { status: 500 }
          )
        }

        console.log('✅ [update-profile] Success:', updatedProfile)

        // Invalidate cache for this user
        const updateCacheKey = `profile_${userId}`
        profileCache.delete(updateCacheKey)
        console.log('[update-profile] Cache invalidated for:', userId)

        return NextResponse.json({
          success: true,
          message: 'Profile updated successfully',
          user: updatedProfile
        })

      case 'update-profile-image':
        if (!userId && !authedClient && !adminClient) {
          return NextResponse.json(
            { error: 'Authentication required', success: false },
            { status: 401 }
          )
        }

        const { image_data } = body

        if (!image_data) {
          return NextResponse.json(
            { error: 'Image data is required', success: false },
            { status: 400 }
          )
        }

        const imageClient = authedClient || adminClient
        if (!imageClient) {
          return NextResponse.json(
            { error: 'Authentication required', success: false },
            { status: 401 }
          )
        }

        let { error: imageUpdateError }: any = await imageClient
          .from('users')
          .update({ 
            profile_image_url: image_data,
            updated_at: new Date().toISOString()
          })
          .eq('id', userId as string)

        if (imageUpdateError && adminClient && (/JWT expired/i.test(imageUpdateError.message || '') || imageUpdateError?.code === 'PGRST303')) {
          ({ error: imageUpdateError } = await adminClient!
            .from('users')
            .update({ 
              profile_image_url: image_data,
              updated_at: new Date().toISOString()
            })
            .eq('id', userId as string))
        }

        if (imageUpdateError) {
          console.error('❌ [update-profile-image] Update failed:', imageUpdateError)
          if ((imageUpdateError as any)?.code === 'PGRST303' || /JWT expired/i.test((imageUpdateError as any)?.message || '')) {
            return NextResponse.json(
              { error: 'Session expired', success: false },
              { status: 401 }
            )
          }
          return NextResponse.json(
            { error: 'Failed to update profile image', success: false, details: imageUpdateError },
            { status: 500 }
          )
        }

        return NextResponse.json({
          success: true,
          image_url: image_data,
          message: 'Profile image updated successfully'
        })

      case 'get-user-profile':
        // Get another user's public profile by userId
        const { userId: targetUserId } = body

        if (!targetUserId) {
          return NextResponse.json(
            { error: 'User ID is required', success: false },
            { status: 400 }
          )
        }

        console.log('[get-user-profile] Fetching public profile for:', targetUserId)
        
        // Use admin client to bypass RLS for public profile viewing
        const profileQuery = adminClient || supabase
        
        const { data: targetProfile, error: targetError } = await profileQuery
          .from('users')
          .select('id, full_name, username, profile_image_url, bio, location, eco_points, total_donations, total_co2_saved, is_seller, is_public, is_active, created_at, followers_count, following_count')
          .eq('id', targetUserId)
          .eq('is_active', true)
          .single()

        if (targetError || !targetProfile) {
          console.error('[get-user-profile] Error:', targetError)
          return NextResponse.json(
            { error: 'Profile not found', success: false },
            { status: 404 }
          )
        }

        // Check if profile is public
        if (!targetProfile.is_public) {
          return NextResponse.json(
            { error: 'This profile is private', success: false },
            { status: 403 }
          )
        }

        // Check if current user is following this profile
        let isFollowing = false
        if (userId) {
          const { data: connection } = await (adminClient || supabase)
            .from('user_connections')
            .select('id')
            .eq('follower_id', userId)
            .eq('following_id', targetUserId)
            .single()
          
          isFollowing = !!connection
        }

        // Recalculate eco_points from accepted donations for this user
        let realEcoPoints = targetProfile.eco_points || 0
        let realCo2Saved = targetProfile.total_co2_saved || 0
        let realDonations = targetProfile.total_donations || 0
        try {
          const donCalcClient = adminClient || supabase
          const { data: acceptedDonations } = await donCalcClient
            .from('donations')
            .select('eco_points_earned, co2_saved')
            .eq('user_id', targetUserId)
            .in('status', ['accepted', 'approved'])

          if (acceptedDonations) {
            realEcoPoints = acceptedDonations.reduce((sum: number, d: any) => sum + (d.eco_points_earned || 0), 0)
            realCo2Saved = Math.round(acceptedDonations.reduce((sum: number, d: any) => sum + (d.co2_saved || 0), 0) * 100) / 100
            realDonations = acceptedDonations.length
          }
        } catch {
          // fall back to stored values
        }

        return NextResponse.json({
          success: true,
          profile: {
            id: targetProfile.id,
            full_name: targetProfile.full_name,
            username: targetProfile.username,
            profile_image_url: targetProfile.profile_image_url,
            bio: targetProfile.bio,
            location: targetProfile.location,
            eco_points: realEcoPoints,
            total_donations: realDonations,
            co2_saved: realCo2Saved,
            is_seller: targetProfile.is_seller || false,
            followers_count: targetProfile.followers_count || 0,
            following_count: targetProfile.following_count || 0,
            created_at: targetProfile.created_at,
            is_following: isFollowing
          }
        })

      case 'get-user-followers': {
        const { userId: targetUserId } = body
        if (!targetUserId) {
          return NextResponse.json({ error: 'User ID is required', success: false }, { status: 400 })
        }

        try {
          const client = adminClient || supabase

          // Get follower ids
          const { data: followerRows, error: followerErr } = await client
            .from('user_connections')
            .select('follower_id')
            .eq('following_id', targetUserId)

          if (followerErr) {
            console.error('[get-user-followers] Error:', followerErr)
            return NextResponse.json({ success: true, followers: [] })
          }

          const followerIds = (followerRows || []).map((r: any) => r.follower_id)
          if (followerIds.length === 0) return NextResponse.json({ success: true, followers: [] })

          const { data: followers, error: usersErr } = await client
            .from('users')
            .select('id, full_name, username, profile_image_url')
            .in('id', followerIds)
            .limit(200)

          if (usersErr) {
            console.error('[get-user-followers] Error fetching user rows:', usersErr)
            return NextResponse.json({ success: true, followers: [] })
          }

          // If we have a viewer, check which of these the viewer follows
          let viewerFollowing: string[] = []
          if (userId) {
            const { data: vf, error: vfErr } = await client
              .from('user_connections')
              .select('following_id')
              .eq('follower_id', userId)
              .in('following_id', followerIds)

            if (!vfErr && vf) viewerFollowing = vf.map((x: any) => x.following_id)
          }

          const formatted = (followers || []).map((u: any) => ({
            id: u.id,
            full_name: u.full_name,
            username: u.username,
            profile_image_url: u.profile_image_url,
            is_following: viewerFollowing.includes(u.id)
          }))

          return NextResponse.json({ success: true, followers: formatted })
        } catch (err) {
          console.error('[get-user-followers] Unexpected error:', err)
          return NextResponse.json({ success: true, followers: [] })
        }
      }

      case 'get-user-following': {
        const { userId: targetUserId } = body
        if (!targetUserId) {
          return NextResponse.json({ error: 'User ID is required', success: false }, { status: 400 })
        }

        try {
          const client = adminClient || supabase

          // Get following ids for the target user
          const { data: followingRows, error: followingErr } = await client
            .from('user_connections')
            .select('following_id')
            .eq('follower_id', targetUserId)

          if (followingErr) {
            console.error('[get-user-following] Error:', followingErr)
            return NextResponse.json({ success: true, following: [] })
          }

          const followingIds = (followingRows || []).map((r: any) => r.following_id)
          if (followingIds.length === 0) return NextResponse.json({ success: true, following: [] })

          const { data: followingUsers, error: usersErr } = await client
            .from('users')
            .select('id, full_name, username, profile_image_url')
            .in('id', followingIds)
            .limit(200)

          if (usersErr) {
            console.error('[get-user-following] Error fetching user rows:', usersErr)
            return NextResponse.json({ success: true, following: [] })
          }

          // If we have a viewer, check which of these the viewer follows
          let viewerFollowing: string[] = []
          if (userId) {
            const { data: vf, error: vfErr } = await client
              .from('user_connections')
              .select('following_id')
              .eq('follower_id', userId)
              .in('following_id', followingIds)

            if (!vfErr && vf) viewerFollowing = vf.map((x: any) => x.following_id)
          }

          const formatted = (followingUsers || []).map((u: any) => ({
            id: u.id,
            full_name: u.full_name,
            username: u.username,
            profile_image_url: u.profile_image_url,
            is_following: viewerFollowing.includes(u.id)
          }))

          return NextResponse.json({ success: true, following: formatted })
        } catch (err) {
          console.error('[get-user-following] Unexpected error:', err)
          return NextResponse.json({ success: true, following: [] })
        }
      }

      case 'follow-user': {
        if (!userId) {
          return NextResponse.json(
            { error: 'Authentication required', success: false },
            { status: 401 }
          )
        }

        const { targetUserId: followTargetId } = body

        if (!followTargetId) {
          return NextResponse.json(
            { error: 'Target user ID is required', success: false },
            { status: 400 }
          )
        }

        if (userId === followTargetId) {
          return NextResponse.json(
            { error: 'Cannot follow yourself', success: false },
            { status: 400 }
          )
        }

        try {
          console.log('[follow-user] User', userId, 'attempting to follow', followTargetId)

          const followClient = authedClient || supabase

          // Check if already following
          const { data: existingFollow, error: checkError } = await followClient
            .from('user_connections')
            .select('id')
            .eq('follower_id', userId)
            .eq('following_id', followTargetId)
            .maybeSingle()

          if (checkError) {
            console.error('[follow-user] Check error:', checkError)
            return NextResponse.json(
              { error: 'Failed to check follow status', success: false },
              { status: 500 }
            )
          }

          if (existingFollow) {
            return NextResponse.json(
              { error: 'Already following this user', success: false },
              { status: 400 }
            )
          }

          // Create connection
          const { error: followError } = await followClient
            .from('user_connections')
            .insert({
              follower_id: userId,
              following_id: followTargetId
            })

          if (followError) {
            console.error('[follow-user] Insert error:', followError)
            return NextResponse.json(
              { error: 'Failed to follow user', success: false },
              { status: 500 }
            )
          }

          // Update follower/following counts (triggers should handle this, but ensure it's immediate)
          try {
            const [followerResult, followingResult] = await Promise.all([
              followClient
                .from('users')
                .select('followers_count')
                .eq('id', followTargetId)
                .single(),
              followClient
                .from('users')
                .select('following_count')
                .eq('id', userId)
                .single()
            ])

            await Promise.all([
              followClient
                .from('users')
                .update({ followers_count: (followerResult.data?.followers_count || 0) + 1 })
                .eq('id', followTargetId),
              followClient
                .from('users')
                .update({ following_count: (followingResult.data?.following_count || 0) + 1 })
                .eq('id', userId)
            ])
          } catch (countError) {
            console.warn('[follow-user] Count update failed (non-fatal):', countError)
          }

          // Send follow notification to the target user
          try {
            const { data: actor } = await followClient
              .from('users')
              .select('id, full_name, username, profile_image_url')
              .eq('id', userId)
              .single()

            const actorName = actor?.full_name || actor?.username || 'Someone'
            
            await createNotification(
              followTargetId,
              userId,
              'new_follower',
              'started following you',
              `/community/profile/${userId}`,
              {
                latestActor: {
                  id: userId,
                  name: actorName,
                  avatar_url: actor?.profile_image_url || undefined,
                }
              }
            )
            console.log('[follow-user] Notification sent to', followTargetId)
          } catch (notifError) {
            console.warn('[follow-user] Notification failed (non-fatal):', notifError)
          }

          return NextResponse.json({
            success: true,
            message: 'Successfully followed user'
          })
        } catch (error) {
          console.error('[follow-user] Unexpected error:', error)
          return NextResponse.json(
            { error: 'An unexpected error occurred', success: false },
            { status: 500 }
          )
        }
      }

      case 'unfollow-user': {
        if (!userId) {
          return NextResponse.json(
            { error: 'Authentication required', success: false },
            { status: 401 }
          )
        }

        const { targetUserId: unfollowTargetId } = body

        if (!unfollowTargetId) {
          return NextResponse.json(
            { error: 'Target user ID is required', success: false },
            { status: 400 }
          )
        }

        try {
          console.log('[unfollow-user] User', userId, 'attempting to unfollow', unfollowTargetId)

          const unfollowClient = authedClient || supabase

          // Check if actually following
          const { data: existingFollow, error: checkError } = await unfollowClient
            .from('user_connections')
            .select('id')
            .eq('follower_id', userId)
            .eq('following_id', unfollowTargetId)
            .maybeSingle()

          if (checkError) {
            console.error('[unfollow-user] Check error:', checkError)
            return NextResponse.json(
              { error: 'Failed to check follow status', success: false },
              { status: 500 }
            )
          }

          if (!existingFollow) {
            return NextResponse.json(
              { error: 'Not following this user', success: false },
              { status: 400 }
            )
          }

          // Delete connection
          const { error: unfollowError } = await unfollowClient
            .from('user_connections')
            .delete()
            .eq('follower_id', userId)
            .eq('following_id', unfollowTargetId)

          if (unfollowError) {
            console.error('[unfollow-user] Delete error:', unfollowError)
            return NextResponse.json(
              { error: 'Failed to unfollow user', success: false },
              { status: 500 }
            )
          }

          // Update follower/following counts
          try {
            const [followerResult, followingResult] = await Promise.all([
              unfollowClient
                .from('users')
                .select('followers_count')
                .eq('id', unfollowTargetId)
                .single(),
              unfollowClient
                .from('users')
                .select('following_count')
                .eq('id', userId)
                .single()
            ])

            await Promise.all([
              unfollowClient
                .from('users')
                .update({ followers_count: Math.max(0, (followerResult.data?.followers_count || 1) - 1) })
                .eq('id', unfollowTargetId),
              unfollowClient
                .from('users')
                .update({ following_count: Math.max(0, (followingResult.data?.following_count || 1) - 1) })
                .eq('id', userId)
            ])
          } catch (countError) {
            console.warn('[unfollow-user] Count update failed (non-fatal):', countError)
          }

          console.log('[unfollow-user] Successfully unfollowed')

          return NextResponse.json({
            success: true,
            message: 'Successfully unfollowed user'
          })
        } catch (error) {
          console.error('[unfollow-user] Unexpected error:', error)
          return NextResponse.json(
            { error: 'An unexpected error occurred', success: false },
            { status: 500 }
          )
        }
      }

      case 'get-barangays':
        try {
          const { data: barangaysData, error: barangaysError } = await supabase
            .from('barangays')
            .select('id, name, municipality')
            .eq('is_active', true)
            .order('name')

          if (barangaysError) {
            console.error('[get-barangays] Error:', barangaysError)
            return NextResponse.json(
              { error: 'Failed to fetch barangays', success: false },
              { status: 500 }
            )
          }

          return NextResponse.json({
            success: true,
            barangays: barangaysData || []
          })
        } catch (error) {
          console.error('[get-barangays] Error:', error)
          return NextResponse.json(
            { error: 'Failed to fetch barangays', success: false },
            { status: 500 }
          )
        }

      case 'get-followers': {
        // Get list of users who follow the specified userId
        const { userId: targetUserId } = body

        if (!targetUserId) {
          return NextResponse.json(
            { error: 'User ID is required', success: false },
            { status: 400 }
          )
        }

        try {
          const client = authedClient || supabase

          // Step 1: Get follower IDs
          const { data: followsData, error: followsError } = await client
            .from('follows')
            .select('follower_id')
            .eq('following_id', targetUserId)

          if (followsError) {
            console.error('[get-followers] Error fetching follows:', followsError)
            return NextResponse.json({ success: true, followers: [] })
          }

          const followerIds = (followsData || []).map((f: any) => f.follower_id).filter(Boolean)
          
          if (followerIds.length === 0) {
            return NextResponse.json({ success: true, followers: [] })
          }

          // Step 2: Get user profiles for those IDs
          const { data: usersData, error: usersError } = await client
            .from('users')
            .select('id, full_name, username, profile_image_url')
            .in('id', followerIds)
            .eq('is_active', true)

          if (usersError) {
            console.error('[get-followers] Error fetching users:', usersError)
            return NextResponse.json({ success: true, followers: [] })
          }

          // Step 3: Check which followers the current user is following (if authenticated)
          let followingSet = new Set<string>()
          if (userId) {
            const { data: userFollowing } = await client
              .from('follows')
              .select('following_id')
              .eq('follower_id', userId)

            followingSet = new Set((userFollowing || []).map((f: any) => f.following_id))
          }

          const followers = (usersData || []).map((u: any) => ({
            id: u.id,
            full_name: u.full_name || u.username || '',
            username: u.username || '',
            profile_image_url: u.profile_image_url || null,
            is_following: followingSet.has(u.id)
          }))

          return NextResponse.json({ success: true, followers })
        } catch (error) {
          console.error('[get-followers] Error:', error)
          return NextResponse.json(
            { error: 'Failed to fetch followers', success: false },
            { status: 500 }
          )
        }
      }

      case 'get-following': {
        // Get list of users that the specified userId follows
        const { userId: targetUserId } = body

        if (!targetUserId) {
          return NextResponse.json(
            { error: 'User ID is required', success: false },
            { status: 400 }
          )
        }

        try {
          const client = authedClient || supabase

          // Step 1: Get following IDs
          const { data: followsData, error: followsError } = await client
            .from('follows')
            .select('following_id')
            .eq('follower_id', targetUserId)

          if (followsError) {
            console.error('[get-following] Error fetching follows:', followsError)
            return NextResponse.json({ success: true, following: [] })
          }

          const followingIds = (followsData || []).map((f: any) => f.following_id).filter(Boolean)
          
          if (followingIds.length === 0) {
            return NextResponse.json({ success: true, following: [] })
          }

          // Step 2: Get user profiles for those IDs
          const { data: usersData, error: usersError } = await client
            .from('users')
            .select('id, full_name, username, profile_image_url')
            .in('id', followingIds)
            .eq('is_active', true)

          if (usersError) {
            console.error('[get-following] Error fetching users:', usersError)
            return NextResponse.json({ success: true, following: [] })
          }

          // Step 3: Check which of these the current user is also following (if authenticated)
          let followingSet = new Set<string>()
          if (userId) {
            const { data: userFollowing } = await client
              .from('follows')
              .select('following_id')
              .eq('follower_id', userId)

            followingSet = new Set((userFollowing || []).map((f: any) => f.following_id))
          }

          const following = (usersData || []).map((u: any) => ({
            id: u.id,
            full_name: u.full_name || u.username || '',
            username: u.username || '',
            profile_image_url: u.profile_image_url || null,
            is_following: followingSet.has(u.id)
          }))

          return NextResponse.json({ success: true, following })
        } catch (error) {
          console.error('[get-following] Error:', error)
          return NextResponse.json(
            { error: 'Failed to fetch following', success: false },
            { status: 500 }
          )
        }
      }

      default:
        return NextResponse.json(
          { error: 'Invalid action specified', success: false },
          { status: 400 }
        )
    }
  } catch (error) {
    console.error('User profile handler error:', error)
    return NextResponse.json(
      { error: 'Internal server error', success: false },
      { status: 500 }
    )
  }
}

